const Q_PHYSICS_2004=[{"id": "objective>Physics>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The refractive index of the medium M in the diagram above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">√ 3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">√ 3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2√ 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">√ 3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: The diagram; <br/> <img src=\"2004/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Refractive</td><td style=\"text-align:center;\">index</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sine of angle of incidence<hr size=\"1\" />sine of angle of refraction</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin60°<hr size=\"1\" />sin30°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which types of mirrors are capable of producing parallel beams of light such as those arising from the head lamps of a car?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cylindrical mirrors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Parabolic mirrors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spherical mirrors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plane mirrors</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parabolic mirrors are used in car headlights because they can produce parallel beams of light. This is due to their unique shape, which causes all incoming light rays that are parallel to the axis of the mirror to reflect and pass through a single point, known as the focus. This property allows the light to be directed in a specific direction, creating a beam of light.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person can focus an object only when it lies within 200cm from him. Which  <br/> spectacles should be used to increase his maximum distance of distinct vision  <br/> to infinity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Concave lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plane glasses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Binoculars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convex lens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The person in this case is short-sighted and can only see objects that are close by. Hence, to correct this, concave lenses are used.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following material media would sound travel faster?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gas</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sound travels faster in solids than in liquids, and faster in liquids than in gases. This is because molecules in a solid medium are much closer together than those in a liquid or gas, allowing sound waves to travel more quickly through the medium. Therefore, sound would travel faster in metal, a solid, than in water, oil (liquids), or gas.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the angle of minimum deviation for a ray which is refracted through an equiangular prism of refractive index 1.4.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">29<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">99<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reflective index, ŋ = 1.4 = sin 1/2(dm+60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>)/sinA/21.4 = sin1/2(dm+60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>)/sin60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>1.4 x 1/2  <br/>  = sin 1/2 (dm + 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>)0.7 = sin 1/2 (dm + 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>), 1/2 (dm + 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>) = sin <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> (0.7)dm + 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> =  <br/>  2 x 44.4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> dm = 88.85 -60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>dm  = 28.85<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>   ≈ 29<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens to the rays in a parallel beam of light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They diverge as they travel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They meet at infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They intersect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They converge as they travel</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A parallel beam of light consists of light rays that are parallel to each other. These rays do not diverge, intersect, or converge as they travel. Instead, they continue to travel in parallel paths, effectively meeting at infinity. Therefore, the correct answer is that they meet at infinity.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If u is the object distance and v the image distance, which of the following expressions gives the linear magnification produced by a convex lens of focal length f?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">U</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">V</span> + F</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">U</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">F</span> - F</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">V</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">F</span> - 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">U</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">F</span> + 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">magnification,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">----------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">---------------</td><td style=\"text-align:center;\">(ii)</td></tr></table></div> <br/> From (ii) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u+v<hr size=\"1\" />uv</td></tr></table></div> <br/> uv = f(u + v) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<hr size=\"1\" />u</td><td style=\"text-align:center;\">(u+v)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">fu+fv<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">fv<hr size=\"1\" />u</td></tr></table></div> <br/> v = f + fm <br/> v - f = fm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v-f<hr size=\"1\" />f</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">-1</td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray of light makes an angle of 35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> with a plane mirror. What is the angle of reflection?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">70<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">65<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically: <br/> <img src=\"2004/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> i + 35° = 90° <br/> i = 55° <br/> From the first law of reflection <br/> i = r = 55°</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of a sound note depends on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">timbre</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmonics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of a sound note is determined by its frequency. Higher frequencies result in higher pitched sounds, while lower frequencies result in lower pitched sounds. Therefore, the correct answer is 'frequency'.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the angle between two vectors P and Q is 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>, the vectors are said to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be perpendicular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest at angle 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">intersect at angle 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the angle between two vectors is 0 degrees, it means the vectors are in the same direction or parallel to each other. Therefore, the correct answer is 'be parallel'.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine whose efficiency is 60% has a velocity ratio of 5. If a force of 500N is applied to lift a load P, what is the magnitude of P?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">750N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4166N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1500N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameter given: <br/> Efficiency, E = 60% <br/> Velocity Ratio, V.R = 5 <br/> Load, W = Unknown <br/> Effort, E = 500N <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> M.A = 3 --------- * <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<hr size=\"1\" />E</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />500</td></tr></table></div> <br/> W = 1500N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 4kg is acted on by a constant force of 12N for 3seconds. The kinetic energy gained by the body at the end of the time is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">162J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">144J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">72J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass (m) = 4kg <br/> Force (F) = 12N <br/> Time (t) = 3s <br/> We need to get the velocity acquired by the body in order to be able to calculate the K.E acquired. <br/> From Newton's 2nd Law of motion <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m(v-u)<hr size=\"1\" />t</td><td style=\"text-align:center;\">--------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> u = 0 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<hr size=\"1\" />t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4v<hr size=\"1\" />3</td></tr></table></div> <br/> v = 9.0m/s <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">81</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">162J</td></tr></table></div></div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As the pressure of a fluid increases, its viscosity .....</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases then decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viscosity is a measure of a fluid's resistance to flow. It is often described as the 'thickness' of a fluid. As the pressure of a fluid increases, the particles of the fluid are compressed together. This increases the intermolecular forces between the particles, making it harder for them to move past each other. As a result, the viscosity of the fluid increases. Therefore, as the pressure of a fluid increases, its viscosity increases.</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Jet-propelled aircraft  <br/>  II. Rocket propulsion  <br/>  III. The recoil of a gun  <br/>  IV. A person walking  <br/>  Which of the above is based on Newton's third law of motion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All the given scenarios (Jet-propelled aircraft, Rocket propulsion, The recoil of a gun, A person walking) are based on Newton's third law of motion. Newton's third law states that for every action, there is an equal and opposite reaction. In a jet-propelled aircraft and rocket propulsion, the action is the expulsion of gas behind the aircraft or rocket and the reaction is the forward movement of the aircraft or rocket. In the recoil of a gun, the action is the bullet being fired and the reaction is the gun moving backwards. In a person walking, the action is the foot pushing against the ground and the reaction is the ground pushing back, causing the person to move forward.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a hydraulic press, a force of 40N is applied on the effort piston of area 0.4m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>.  <br/>  If the force exerted on the load piston is 400N, the area of the large piston is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> This question tests your knowledge of hydraulic <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40<hr size=\"1\" />0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">400<hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 100kg box is pushed along a road with a force of 500N. If the box moves with a uniform  velocity,  the coefficient of friction between the box and the road is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Force, F = 500N,  <br/> Mass, m = 100kg ;   <br/> The box is pushed with uniform velocity, i.e the net force on the box is zero <br/> <img src=\"2004/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> Fr (Frictional force), U = coefficient of friction <br/> 500 - Fr = 0 <br/> 500 = Fr ------------- * <br/> 500 = Umg <br/> 500 = U(100)(10) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td></tr></table></div></div>", "topic": "FRICTION"}, {"id": "objective>Physics>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earth is four times the size of the moon and the acceleration due to gravity on the earth is 80 times that on the moon. The ratio of the mass of the moon to that of the earth is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 : 320</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 1280</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">-----------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = mass of the planetary body <br/> g = Gravitational intensity/acceleration due to gravity <br/> R = Radius of the planet <br/> From the information given in the question, <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 4R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> ----------------------- * <br/> g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 80g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> -------------------- * * <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> : M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = Unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">From</td><td style=\"text-align:center;\">g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">,</td><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">constant</td><td style=\"text-align:center;\">factor</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gR<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div> <br/> G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">earth</span> = G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">moon</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">80g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>×(4R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>×R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">80*time*16<hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1280<hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><hr size=\"1\" />1280</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1280</td></tr></table></div></div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows forces 4N,6N,10N and 8N which act at a point O in the directions indicated. <br/>  The net horizontal force is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7 √ 3N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">√ 3N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: the diagram <br/> <img src=\"2004/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> Get the magnitude of the resolved component of each force along the horizontal direction, then add up everything arithmetically to get the net horizontal force. <br/> - For the 8H force <br/> |F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>| = 8cos60° = 4.0N <br/> - For the 6N force <br/> |F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>| = 6cos60° = 3.0N <br/> - For the 10N force <br/> |F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>| = 10N <br/> - For the 4N force <br/> |F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>| = -4N <br/> Net Horizontal Force = 4 + 3 + 10 - 4 = 13N</div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radio isotope has a decay constant of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The average life of the radio isotope is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameter given: <br/> Decay constant, λ = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Half-life, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.693<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1<hr size=\"1\" />2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.693<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span></td></tr></table></div> <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = 6.93 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>s</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A moving coil galvanometer has a full scale deflection of 3A equivalent to 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>deflection. The sensitivity of the instrument is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sensitivity ⇒  Current/Angle   ⇒  <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">ϴ</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">T</span> <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">30</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span> <br/> = 10</div>", "topic": "MAGNETIC FIELD : MOVING COIL AND MOVING IRON INSTRUMENTS"}, {"id": "objective>Physics>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The binding energy of helium 4 He 2 is  <br/> [atomic mass of proton = 1.00783 U, atomic mass of neutron  = 1.00867 U]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.017 U</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.033 U</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.033 U</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.330 U</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Binding energy = mass difference of nucleons and nucleus;  <br/>  (2 x 1.00783 + 2 x 1.00867) – 4 = 4.33u – 4u = 0.033u.</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a tuned radio receiver, L, C series circuit for resonance, the inductive and capacitive reactance X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> and X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> respectively are related as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= 2X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a tuned radio receiver, the inductive reactance (X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>) and capacitive reactance (X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span>) are equal at resonance. This is because at resonance, the impedance of the circuit is minimum and the circuit is purely resistive. This means that the inductive and capacitive reactances cancel each other out, hence X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span>.</div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The particle and wave nature of matter are demonstrated in the equation</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">λ=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">h</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">p</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">λ=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">c</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">f</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">λ=2d sineθ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">λ=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">hc</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">E</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation λ=h/p demonstrates the particle and wave nature of matter. This equation is known as the de Broglie wavelength equation. It shows that every particle with momentum (p) has a corresponding wavelength (λ), which is a characteristic of waves. Here, h is the Planck's constant.</div>", "topic": "ELEMENTARY MODERN PHYSICS : WAVE-PARTICLE PARADOX DUALITY OF MATTER"}, {"id": "objective>Physics>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For semi-conductors to have negative temperature coefficient of resistance implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they have electrons and holes at high temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their resistance is constantly changing with temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their resistance increases with temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their resistance decreases with temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Semi-conductors generally have negative co-efficient of resistance because their resistance decreases with temperature.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fluorescent tubes produce light by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">refraction of light by gas molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excitation of gas molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction of solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermal agitation of electrons in the tube</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fluorescent tubes produce light by the excitation of gas molecules. When an electric current is passed through the gas in the tube, the gas molecules get excited and emit light. This process is known as fluorescence.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a reversed biased junction diode,current flows in by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons alone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">majority carriers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minority carriers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive holes alone</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a reverse biased junction diode, current flows in by minority carriers. In a reverse bias, the p-side is connected to the negative terminal of the battery and the n-side to the positive terminal. This increases the barrier potential and only a small leakage current, due to the minority carriers, flows through the diode.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The energy stored in an inductor of inductance 5mH when a current of 6A  <br/> flows through it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Energy, <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">LI<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">6X10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>J</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.0</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</td></tr></table></div></div>", "topic": "ELECTROMAGNETIC INDUCTION : INDUCTANCE"}, {"id": "objective>Physics>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">X-rays can be used in the study of crystal structures because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have an extremely  short wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have a very long-reaching wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are very fast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are invisible</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are used in the study of crystal structures because they have an extremely short wavelength. This short wavelength is comparable to the distances between atoms in a crystal, allowing the X-rays to interact with the crystal in a way that reveals its internal structure. This is the principle behind X-ray crystallography.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An a.c. circuit of e.m.f. 12V has a resistor of resistance 8Ω connected in series to an inductor of inductive reactance 16Ω and a capacitor of 20 capacitive reactance 10Ω. The current flowing in the circuit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.4A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> E.m.f, E = 12v <br/> Resistance, R = 8ohms <br/> Inductive reactance, X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 16 ohms <br/> Capacitive reactance, X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span> = 10 ohms <br/> <img src=\"2004/5.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: V = IZ --------------- (i) <br/> Z<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = (X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> - X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> --------------- (ii) <br/> From (2) <br/> Z<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = (16 - 10)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Z<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Z<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 100 <br/> Z = 10 ohms <br/> Apply equation (i) <br/> 12 = I × 10 <br/> I = 1.2A</div>", "topic": "SIMPLE A. C. CIRCUITS : R-L-C CIRCUITS"}, {"id": "objective>Physics>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A generator-manufacturing company was contracted to produce an a.c.dynamo but inadvertently produced a d.c. dynamo. <br/>  To correct this error, the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commutator should  be  replaced with slip rings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commutator should be replaced with split rings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Armature coil should be made of aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Armature coil should be made of silver</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between an AC dynamo (alternator) and a DC dynamo (generator) is the method of taking the current off the rotating coil. In a DC dynamo, this is done using a commutator, which allows the current to always flow in the same direction. In an AC dynamo, this is done using slip rings, which allow the current to alternate its direction. Therefore, to convert a DC dynamo into an AC dynamo, the commutator should be replaced with slip rings.</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Transverse  waves  can  be  distinguished from longitudinal waves using the characteristic of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polarization is a typical characteristic of transverse waves. Longitudinal waves cannot undergo polarization.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man exerts a pressure of 2.8  x  10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> on the ground and has 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> of  his  feet  in  contact  with  the  ground. The weight of the man is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">112N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">102N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Pressure, P = 2.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Area, A = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Weight, W = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Pressure</td><td style=\"text-align:center;\">(P)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Normal Force<hr size=\"1\" />Area</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2.8</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Weight<hr size=\"1\" />4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> Weight = 112N</div>", "topic": "PRESSURE"}, {"id": "objective>Physics>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When  left  in  a  freezer, a bottle full of water cracks on freezing into ice because of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in the volume of water.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contraction of the bottle.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expansion of the bottle.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the volume of water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When water is cooled from 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, which freezing water expands, this expansion of water on freezing cause an increase in the volume of water which cause cracking  of the bottle.</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The change  in volume when 450kg of ice is completely melted is  <br/> [Density of ice = 900 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, density of water = 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.45m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.50m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that when a substance is melted, its mass does not change, only its volume and density change <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall;</td><td style=\"text-align:center;\">Density</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />volume</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />v</td><td style=\"text-align:center;\">-------------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> m = ρv ----------------------- (2) <br/> Change in volume = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">450<hr size=\"1\" />900</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td></tr></table></div> <br/> volume of water (changed ice) = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">450</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1000</span> <br/> Note : density of water  = 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> = 0.45 <br/> change in volume  = 0.5 - 0.45 <br/>  = 0.05m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a force of 50N stretches a wire from 20m to 20.01m, what is the amount of force  required  to  stretch  the  same material from 20m to 20.05m?  <br/>  [Density of water = 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200N.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Force, F = K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>   F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>e1 = 20.01 - 20 = 0.01  <br/>  m.e = 20.05 -20  = 0.05m50/0.01  = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/0.05F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 250N  <br/>  F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 5000 x 0.05.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tea pots are often silver-coated to prevent heat loss by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convection and conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radiation only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convection only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silver coating on tea pots helps to prevent heat loss by radiation. Radiation is the transfer of heat energy by electromagnetic waves. Silver is a good reflector of these waves, hence it prevents heat loss by reflecting the heat back into the pot.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The phase difference between waves P and Q in the diagram above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">π/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">π/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">π</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">phase</td><td style=\"text-align:center;\">difference</td><td style=\"text-align:center;\">between</td><td style=\"text-align:center;\">waves</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">diagram</td><td style=\"text-align:center;\">above</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />2.</td></tr></table></div></td></tr></table></div></div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Metal rods of length 20m each are laid end  to  end  to  form  a  bridge  at   25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.What  gap  will  be  provided  between consecutive  rails  for  the bridge  to withstand 75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C? <br/>  <br/> [α = 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.22m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.02m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">α = 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,  L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20m, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C,  θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 75 – 25 = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆L<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>∆θ</td></tr></table></div> <br/> ∴  ∆L = α L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>∆θ = 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> x 20 x 50 = 0.02m.</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 50W electric heater is used to heat a metal block of mass 5kg. If in 10 minutes, a temperature rise of 12<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is achieved, the specific heat capacity  of the metal is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">500 J kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">130 J kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">390 J kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">400 J kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The specific heat capacity (c) of a substance is the amount of heat energy required to raise the temperature of a unit mass of the substance by one degree Celsius. It can be calculated using the formula Q = mcΔT, where Q is the heat energy supplied, m is the mass of the substance, and ΔT is the change in temperature. In this case, Q = 50W * 10min = 30000J, m = 5kg, and ΔT = 12°C. Solving for c gives c = Q/(m*ΔT) = 30000J/(5kg*12°C) = 500 J kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Therefore, the correct option is 1.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Wavelength  <br/> II. Medium of propagation  <br/> III. Wave velocity IV. Frequency  <br/> V. Energy  <br/> Which of the above are used for characterizing waves?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, IV and V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Waves can be characterized by Wavelength, wave velocity , frequency , period and amplitude.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument used for securing a large number of similar charges  by induction is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capacitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrophorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electroscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proof-plane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electrophorus is designed for collecting numerous similar charges through electrostatic induction. It consists of a metal plate and an insulating handle. To charge it, the metal plate briefly touches a charged object, acquiring a similar charge. Lifting it isolates the charge. The charged plate can then induce a charge on another object, allowing for the transfer of charge. This unique feature enables the electrophorus to store and transfer numerous charges for experiments. <br/>  <br/> Regarding other options: <br/>  <br/> A capacitor (A) stores charge within itself but isn't used for collecting charges by induction. <br/> An electroscope (C) detects charges but doesn't secure or store them. <br/> A proof-plane (D) transfers small charges for testing, not securing large ones. <br/> The electrophorus stands out for its ability to collect and hold many charges through electrostatic induction.</div>", "topic": "ELECTROSTATICS : CHARGING A BODY"}, {"id": "objective>Physics>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A steady current of 2A flows in a coil of emf 12V for 0.4s. A back emf of 3V was induced during this period. The stored energy in the loop that  <br/> can be utilized is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.2J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.6J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy stored in the loop can be calculated using the formula for electrical power, P = IV, where I is the current and V is the voltage. The power is then multiplied by the time to get the energy, E = Pt. The voltage here is the difference between the applied emf and the back emf, which is 12V - 3V = 9V. So, the energy is E = (2A)(9V)(0.4s) = 7.2J. Therefore, the correct answer is 7.2J.</div>", "topic": "CURRENT ELECTRICITY: ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 16mA of current flows through a conductor in one second, the number of electrons transported per second is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-18</span>)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Current, I = 16mA = 16 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>A = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>A <br/> Time, t = 1s <br/> Number of electrons, n = unknown <br/> Recall; <br/> Q = ne ---------- * <br/> Also recall Q = It <br/> It = ne <br/> 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × 1 = n × 1.60 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> <br/> n = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span> electrons</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between X-rays and gamma rays is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X-rays arise from energy changes in the  electronic  structure  of  atoms while  gamma  rays  come  from  the nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are electromagnetic radiations while gamma rays are negatively charged radiations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays have higher frequencies than gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are more penetrating than gamma rays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between x-rays and gamma rays is that x-rays arise from energy changes in the electronic structure of atoms while gamma rays come from the nucleus.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS~~ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>   In  the  diagram  above,  the  ratio  of  the electric power dissipated in the  6Ω and 3Ω resistors respectively is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 : 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2004/6.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td><td style=\"text-align:center;\">------------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> The two resistors are arranged in parallel, so they have the same voltage, i.e 12v <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6Ω</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(12)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">144<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24W</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3Ω</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(12)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">144<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">48W</td></tr></table></div> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6Ω</span> : P_(3Ω0 = 24W : 48W = 1 : 2 </div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To protect a material from the influence of an external magnetic field the material should be kept in a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">square steel ring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loop of copper wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">triangular zinc ring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soft iron ring</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A soft iron ring is used to protect a material from the influence of an external magnetic field. This is because soft iron has high magnetic permeability, meaning it can easily become magnetized and demagnetized. When an external magnetic field is applied, the soft iron ring becomes magnetized and attracts the magnetic field lines towards itself, thus shielding the material inside the ring.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an electrolyte?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Grape juice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sugar solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paraffin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An electrolyte is a substance that produces an electrically conducting solution when dissolved in a polar solvent, such as water. Grape juice, being a fruit juice, contains various types of ions, such as citrate ions, and can therefore conduct electricity, making it an electrolyte.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electrical appliances in homes are normally earthed so that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both the a.c. and d.c. sources can be used.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a person touching the appliances is safe from electric shock.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the appliances are maintained at a higher p.d. than the earth.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the appliances are maintained at a lower p.d. than the earth.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrical appliances in homes are normally earthed so that a person touching the appliance is safe from electric shock.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell whose internal resistance is 0.5Ω delivers a current of 4A to an external resistor. The lost voltage of the cell is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.250V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.000V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.125V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.000V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Internal resistance, r = 0.5 Ω ; <br/> Current,  I = 4A, <br/> lost voltage =? <br/>  Ir = 0.5 x 4 = 2v.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given three capacitors 0.3µF, 0.5µF and 0.2µF, the joined capacitance   <br/> when arranged to give minimum capacitance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.3 µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 µF</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When arranged to give minimum capacitance implies that the capacitors are arranged in series <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.5</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2+1.2+3<hr size=\"1\" />0.6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6<hr size=\"1\" />6.2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />62</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.1μF</td></tr></table></div></div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}];
